// ─── 1. Parse dados_empresa ───────────────────────
const triggerJson = $('Input').first().json;

let dadosEmpresaRaw = triggerJson.dados_empresa;
let dadosParsed = {};

try {
  if (typeof dadosEmpresaRaw === 'string') {
    dadosParsed = JSON.parse(dadosEmpresaRaw);
  } else if (typeof dadosEmpresaRaw === 'object' && dadosEmpresaRaw !== null) {
    dadosParsed = dadosEmpresaRaw;
  }
} catch (e) {
  throw new Error('❌ Falha ao parsear dados_empresa: ' + e.message);
}

const de = dadosParsed.dados_empresa        || {};
const ie = dadosParsed.informacoes_empresa  || {};

const instagram     = de.instagram     || de.Instagram     || '';
const nome_perfil   = de.nome_perfil   || de.Nome_perfil   || '';
const imagem_perfil = de.Imagem_perfil || de.imagem_perfil || '';
const icone         = de.icone         || de.Icone         || '';
const nome          = dadosParsed.nome    || '';
const contato       = dadosParsed.contato || '';
const chat_id       = dadosParsed.chat_id || '';
const cliente       = ie.cliente || '';
const ramo          = ie.ramo    || '';

// ─── 2. Gera unique_id ─────────────────────────────
const ts      = Date.now().toString(36).toUpperCase();
const rand    = Math.floor(Math.random() * 99999).toString(36).toUpperCase().padStart(3, '0');
const raw     = (ts + rand).replace(/[^A-Z0-9]/g, '');
const unique_id = raw.slice(-8).padStart(8, '0');

// ─── 3. Dados do bloco de textos/imagens ────────────
const items = $input.all();
if (!items || items.length === 0) throw new Error('⚠️ Sem input.');
const d = items[0].json;

function limparTexto(txt) {
  return (txt || '').replace(/\s+/g, ' ').trim();
}

// ─── Helpers de split ────────────────────────────────
function splitFrases(texto) {
  return limparTexto(texto).split('.').map(f => f.trim()).filter(Boolean);
}

// Padrão A: bloco_1 = frase 1 | bloco_2 = frases 2+3  (imgs 1, 3, 5)
function splitA(texto) {
  const f = splitFrases(texto);
  if (f.length >= 2) return { bloco_1: f[0] + '.', bloco_2: f.slice(1).join('. ').trim() + '.' };
  if (f.length === 1) {
    const p = f[0].split(' ');
    const m = Math.ceil(p.length / 2);
    return { bloco_1: p.slice(0, m).join(' ') + '.', bloco_2: p.slice(m).join(' ') + '.' };
  }
  return { bloco_1: '', bloco_2: '' };
}

// Padrão B: bloco_1 = frases 1+2 | bloco_2 = frase 3  (imgs 2, 4, 6)
function splitB(texto) {
  const f = splitFrases(texto);
  if (f.length >= 3) return { bloco_1: f.slice(0, 2).join('. ').trim() + '.', bloco_2: f.slice(2).join('. ').trim() + '.' };
  if (f.length === 2) return { bloco_1: f[0] + '.', bloco_2: f[1] + '.' };
  if (f.length === 1) return { bloco_1: f[0] + '.', bloco_2: '' };
  return { bloco_1: '', bloco_2: '' };
}

// ─── Split por imagem ────────────────────────────────
const img1 = splitA(d.texto_imagem_1);
const img2 = splitB(d.texto_imagem_2);
const img3 = splitA(d.texto_imagem_3);
const img4 = splitB(d.texto_imagem_4);
const img5 = splitA(d.texto_imagem_5);
const img6 = splitB(d.texto_imagem_6);

const legenda = d.legenda || triggerJson.legenda || '';

return [{
  json: {
    // Blocos de texto para HTML
    html_imagem_1: { bloco_1: img1.bloco_1, bloco_2: img1.bloco_2 },
    html_imagem_2: { bloco_1: img2.bloco_1, bloco_2: img2.bloco_2 },
    html_imagem_3: { bloco_1: img3.bloco_1, bloco_2: img3.bloco_2 },
    html_imagem_4: { bloco_1: img4.bloco_1, bloco_2: img4.bloco_2 },
    html_imagem_5: { bloco_1: img5.bloco_1, bloco_2: img5.bloco_2 },
    html_imagem_6: { bloco_1: img6.bloco_1, bloco_2: img6.bloco_2 },

    // Links ou queries Unsplash
    query_ou_imagem_1: d.query_ou_imagem_1 || '',
    query_ou_imagem_2: d.query_ou_imagem_2 || '',
    query_ou_imagem_3: d.query_ou_imagem_3 || '',
    query_ou_imagem_4: d.query_ou_imagem_4 || '',
    query_ou_imagem_5: d.query_ou_imagem_5 || '',
    query_ou_imagem_6: d.query_ou_imagem_6 || '',

    // Prompts GPT Image 1
    prompt_image_1: d.prompt_image_1 || '',
    prompt_image_2: d.prompt_image_2 || '',
    prompt_image_3: d.prompt_image_3 || '',
    prompt_image_4: d.prompt_image_4 || '',
    prompt_image_5: d.prompt_image_5 || '',
    prompt_image_6: d.prompt_image_6 || '',

    // Dados da empresa
    instagram,
    nome_perfil,
    imagem_perfil,
    icone,
    nome,
    contato,
    chat_id,
    cliente,
    ramo,

    // Legenda e ID
    legenda,
    unique_id
  }
}];

