=<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8" />
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;700&family=Montserrat:wght@400;500;700&display=swap" rel="stylesheet">
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
html, body { width: 1080px; background: #ffffff; font-family: 'Inter', sans-serif; }
.card { width: 1080px; padding: 72px 88px 72px 88px; display: flex; flex-direction: column; }
.header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 44px; }
.header-left { display: flex; align-items: center; gap: 18px; }
.avatar { width: 90px; height: 90px; border-radius: 50%; overflow: hidden; flex-shrink: 0; border: 2.5px solid #e5e7eb; }
.avatar img { width: 100%; height: 100%; object-fit: cover; }
.profile-info { display: flex; flex-direction: column; gap: 4px; }
.empresa-nome { font-family: 'Montserrat', sans-serif; font-size: 42px; font-weight: 500; color: #0f172a; line-height: 1; text-transform: uppercase; letter-spacing: 1px; display: inline-block; transform: scaleX(1.08); transform-origin: left; }
.instagram-handle { font-family: 'Inter', sans-serif; font-size: 27px; font-weight: 400; color: #6b7280; }
.icone-right { font-family: 'Courier New', monospace; font-size: 60px; font-weight: 900; color: #0f172a; letter-spacing: -2px; align-self: flex-start; flex-shrink: 0; }
.icone-right-img { width: 64px; height: 64px; object-fit: contain; align-self: flex-start; flex-shrink: 0; }
.textos { margin-bottom: 48px; }
.bloco1 { font-family: 'Inter', sans-serif; font-size: 46px; font-weight: 400; color: #000000; line-height: 1.25; margin-bottom: 20px; letter-spacing: -0.5px; }
.bloco2 { font-family: 'Inter', sans-serif; font-size: 46px; font-weight: 400; color: #000000; line-height: 1.25; letter-spacing: -0.5px; }
.foto-container { width: 100%; }
.foto-container img { width: 100%; height: 660px; object-fit: cover; border-radius: 18px; display: block; }
</style>
</head>
<body>
<div class="card">
  <div class="header">
    <div class="header-left">
      <div class="avatar"><img src="{{ $('Gera blocos de textos para os HTMLs1').item.json.imagem_perfil }}" /></div>
      <div class="profile-info">
        <span class="empresa-nome">{{ $('Gera blocos de textos para os HTMLs1').item.json.nome_perfil }}</span>
        <span class="instagram-handle">{{ $('Gera blocos de textos para os HTMLs1').item.json.instagram }}</span>
      </div>
    </div>
    {{ $('Gera blocos de textos para os HTMLs1').item.json.icone ? ($('Gera blocos de textos para os HTMLs1').item.json.icone.startsWith('http') ? '<img class="icone-right-img" src="' + $('Gera blocos de textos para os HTMLs1').item.json.icone + '" />' : '<div class="icone-right">' + $('Gera blocos de textos para os HTMLs1').item.json.icone + '</div>') : '' }}
  </div>
  <div class="textos">
    <div class="bloco1">{{ $('Gera blocos de textos para os HTMLs1').item.json.html_imagem_1.bloco_1 }}</div>
    <div class="bloco2">{{ $('Gera blocos de textos para os HTMLs1').item.json.html_imagem_1.bloco_2 }}</div>
  </div>
  <div class="foto-container"><img src="{{ $json.foto_slide }}" /></div>
</div>
</body>
</html>

