// --- Captura usa_blog do trigger ---
const usa_blog = $('Input').first().json?.usa_blog ?? false;

// --- Captura o retorno da IA ---
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('⚠️ Nenhum retorno da IA encontrado.');
}

// --- Extrai o texto bruto de qualquer estrutura possível do LangChain ---
function extrairTexto(item) {
  const j = item.json;

  // Tentativas diretas
  if (j?.output && typeof j.output === 'string') return j.output;
  if (j?.text && typeof j.text === 'string') return j.text;
  if (j?.response?.text) return j.response.text;
  if (j?.message?.content && typeof j.message.content === 'string') return j.message.content;
  if (j?.content && typeof j.content === 'string') return j.content;

  // Array de content blocks (OpenAI/Anthropic style)
  if (Array.isArray(j?.content)) {
    const bloco = j.content.find(c => c.type === 'text');
    if (bloco?.text) return bloco.text;
  }

  // Aninhamento extra do LangChain agent v3
  if (j?.output?.content && typeof j.output.content === 'string') return j.output.content;
  if (Array.isArray(j?.output?.content)) {
    const bloco = j.output.content.find(c => c.type === 'text');
    if (bloco?.text) return bloco.text;
  }

  // Tenta serializar tudo e extrair JSON de dentro
  try {
    const str = JSON.stringify(j);
    return str;
  } catch(_) {
    return '';
  }
}

// --- Extrai e limpa o JSON da resposta ---
let resultado = null;

for (const item of items) {
  let output = extrairTexto(item);

  if (!output) continue;

  // Remove blocos de código markdown
  output = output
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // Localiza o JSON dentro do texto
  const inicio = output.indexOf('{');
  const fim = output.lastIndexOf('}');
  if (inicio === -1 || fim === -1) continue;

  output = output
    .slice(inicio, fim + 1)
    .replace(/[\u201C\u201D]/g, '"')
    .replace(/[\u2018\u2019]/g, "'")
    .replace(/\t/g, ' ')
    .replace(/[\u0000-\u0019]+/g, ' ');

  try {
    resultado = JSON.parse(output);
    break;
  } catch (err) {
    // Tenta corrigir JSON quebrado: remove trailing commas
    try {
      const corrigido = output
        .replace(/,\s*}/g, '}')
        .replace(/,\s*]/g, ']');
      resultado = JSON.parse(corrigido);
      break;
    } catch (_) {
      console.log('JSON inválido mesmo após correção:', err.message);
    }
  }
}

// --- Validações ---
if (!resultado) {
  // Loga o raw para debug
  const raw = extrairTexto(items[0]);
  throw new Error('❌ Não foi possível extrair JSON válido da resposta da IA. RAW: ' + String(raw).slice(0, 500));
}
if (!resultado.textos || !resultado.imagens) {
  throw new Error('❌ JSON retornado está incompleto. Chaves presentes: ' + Object.keys(resultado).join(', '));
}

// --- Monta o retorno final ---
const textos  = resultado.textos        ?? {};
const imagens = resultado.imagens       ?? {};
const prompts = resultado.prompts_image ?? {};

return [{
  json: {
    // Textos dos slides
    texto_imagem_1: textos.imagem_1 || '',
    texto_imagem_2: textos.imagem_2 || '',
    texto_imagem_3: textos.imagem_3 || '',
    texto_imagem_4: textos.imagem_4 || '',
    texto_imagem_5: textos.imagem_5 || '',
    texto_imagem_6: textos.imagem_6 || '',

    // Links ou queries Unsplash
    query_ou_imagem_1: imagens.imagem_1 || '',
    query_ou_imagem_2: imagens.imagem_2 || '',
    query_ou_imagem_3: imagens.imagem_3 || '',
    query_ou_imagem_4: imagens.imagem_4 || '',
    query_ou_imagem_5: imagens.imagem_5 || '',
    query_ou_imagem_6: imagens.imagem_6 || '',

    // Prompts GPT Image 1
    prompt_image_1: prompts.imagem_1 || '',
    prompt_image_2: prompts.imagem_2 || '',
    prompt_image_3: prompts.imagem_3 || '',
    prompt_image_4: prompts.imagem_4 || '',
    prompt_image_5: prompts.imagem_5 || '',
    prompt_image_6: prompts.imagem_6 || '',

    // Prompt principal e legenda
    prompt_image: resultado.prompt_image || '',
    legenda:      resultado.legenda      || '',

    // Flag de controle
    usa_blog: usa_blog
  }
}];

const item = $input.first().json;
const blocos = $('Gera blocos de textos para os HTMLs1').first().json;

const slide_urls = [
  item.imagem1_url,
  item.imagem2_url,
  item.imagem3_url,
  item.imagem4_url,
  item.imagem5_url,
  item.imagem6_url
].filter(u => !!u);

return [{
  json: {
    slide_urls,
    slides: {
      slide_1: item.imagem1_url || '',
      slide_2: item.imagem2_url || '',
      slide_3: item.imagem3_url || '',
      slide_4: item.imagem4_url || '',
      slide_5: item.imagem5_url || '',
      slide_6: item.imagem6_url || ''
    },
    nome_arquivo: `carrossel_${blocos.cliente || 'cliente'}.pdf`,
    legenda:   blocos.legenda   || '',
    unique_id: blocos.unique_id || '',
    chat_id:   blocos.chat_id   || '',
    nome:      blocos.nome      || '',
    contato:   blocos.contato   || '',
    cliente:   blocos.cliente   || '',
    ramo:      blocos.ramo      || ''
  }
}];

const pdfItem = $input.first();
const nome = $('Retorna url dos slides').first().json.nome_arquivo;
pdfItem.binary.data.fileName = nome;
return [pdfItem];

